const agentResponse = $input.first().json;
const results = agentResponse.results || [];

const enriched = results.map(r => ({
  alert: r.alert_name,
  namespace: r.namespace,
  severity: r.severity,
  classification: r.classification,
  rootCause: r.root_cause,
  autoRemediated: r.auto_remediation_applied,
  prUrl: r.git_pr_url || 'none',
  argoCDSync: r.argocd_sync_triggered,
  runbook: (r.runbook || []).map(step => `${step.order}. [${step.action}] ${step.description}`).join('\n'),
  investigationSteps: (r.investigation_log || []).length,
}));

if (enriched.length === 0) {
  return [{ json: { alert: 'unknown', namespace: 'unknown', severity: 'unknown', classification: 'Unknown', rootCause: 'No results from agent', autoRemediated: false, prUrl: 'none', argoCDSync: false, runbook: '', investigationSteps: 0 } }];
}

return enriched.map(e => ({ json: e }));

const data = $input.first().json;
const timestamp = new Date().toISOString();

const logEntry = {
  timestamp,
  alert: data.alert,
  namespace: data.namespace,
  severity: data.severity,
  classification: data.classification,
  autoRemediated: data.autoRemediated,
  prUrl: data.prUrl,
};

console.log('AUDIT:', JSON.stringify(logEntry));

return [{ json: { ...data, auditLogged: true, timestamp } }];
